// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.IOException;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Arrays;
import java.util.Comparator;
import java.util.stream.Collectors;

import javax.tools.JavaCompiler;
import javax.tools.ToolProvider;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class QueryModelVisitorCompatibilityTest {

	@TempDir
	Path tempDir;

	@Test
	void directVisitorImplementationsCanIgnoreLateral() throws IOException {
		JavaCompiler compiler = ToolProvider.getSystemJavaCompiler();
		assertThat(compiler).isNotNull();

		Path source = tempDir.resolve("LegacyVisitor.java");
		Files.writeString(source, legacyVisitorSource(), StandardCharsets.UTF_8);

		int exitCode = compiler.run(null, null, null,
				"-classpath", System.getProperty("java.class.path"),
				"-d", tempDir.toString(),
				source.toString());

		assertThat(exitCode).isZero();
	}

	private static String legacyVisitorSource() {
		return """
				import org.eclipse.rdf4j.query.algebra.QueryModelVisitor;

				final class LegacyVisitor implements QueryModelVisitor<RuntimeException> {
				%s
				}
				""".formatted(abstractMethodsExceptLateral());
	}

	private static String abstractMethodsExceptLateral() {
		return Arrays.stream(QueryModelVisitor.class.getMethods())
				.filter(method -> Modifier.isAbstract(method.getModifiers()))
				.filter(method -> !isLateralMeet(method))
				.sorted(Comparator.comparing(Method::getName)
						.thenComparing(method -> method.getParameterTypes()[0].getName()))
				.map(QueryModelVisitorCompatibilityTest::methodImplementation)
				.collect(Collectors.joining(System.lineSeparator()));
	}

	private static boolean isLateralMeet(Method method) {
		return method.getName().equals("meet") && method.getParameterTypes()[0] == Lateral.class;
	}

	private static String methodImplementation(Method method) {
		Class<?> parameterType = method.getParameterTypes()[0];
		return """
					@Override
					public void %s(%s node) {
					}
				""".formatted(method.getName(), parameterType.getName());
	}
}
